func TestMultiInstance_ElementVariable(t *testing.T) {
	ctx := context.Background()
	s := memstore.New()
	t.Cleanup(func() { s.Close() })
	e := NewProcessEngine(s)

	// Use sequential mode so element variable is not overwritten.
	def := &spec.ProcessDefinition{
		ID:      "mi_var",
		Key:     "mi_var",
		Version: 1,
		Elements: map[string]spec.FlowElement{
			"start": &spec.StartEvent{ID: "start"},
			"task": &spec.UserTask{
				ID: "task",
				LoopCharacteristics: &spec.LoopCharacteristics{
					IsSequential:    true,
					Collection:      "items",
					ElementVariable: "current",
				},
			},
			"end": &spec.EndEvent{ID: "end"},
		},
		SequenceFlows: []*spec.SequenceFlow{
			{ID: "sf1", SourceRef: "start", TargetRef: "task"},
			{ID: "sf2", SourceRef: "task", TargetRef: "end"},
		},
		StartEventID: "start",
	}
	if err := s.CreateProcessDefinition(ctx, def); err != nil {
		t.Fatal(err)
	}

	pi, err := e.StartProcessInstance(ctx, "mi_var", map[string]any{"items": []any{"first", "second"}})
	if err != nil {
		t.Fatalf("StartProcessInstance: %v", err)
	}

	// First item variable should be set.
	item, err := s.GetVariable(ctx, pi.ID, "current")
	if err != nil {
		t.Fatal(err)
	}
	if item != "first" {
		t.Errorf("expected current = first, got %v", item)
	}
}

func TestMultiInstance_NoLoopCharacteristics(t *testing.T) {
	ctx := context.Background()
	s := memstore.New()
	t.Cleanup(func() { s.Close() })
	e := NewProcessEngine(s)

	// Regular UserTask (no MI) should behave normally.
	def := &spec.ProcessDefinition{
		ID:      "normal",
		Key:     "normal",
		Version: 1,
		Elements: map[string]spec.FlowElement{
			"start": &spec.StartEvent{ID: "start"},
			"task":  &spec.UserTask{ID: "task"},
			"end":   &spec.EndEvent{ID: "end"},
		},
		SequenceFlows: []*spec.SequenceFlow{
			{ID: "sf1", SourceRef: "start", TargetRef: "task"},
			{ID: "sf2", SourceRef: "task", TargetRef: "end"},
		},
		StartEventID: "start",
	}
	if err := s.CreateProcessDefinition(ctx, def); err != nil {
		t.Fatal(err)
	}

	pi, err := e.StartProcessInstance(ctx, "normal", nil)
	if err != nil {
		t.Fatalf("StartProcessInstance: %v", err)
	}
	activities, _ := s.ListActiveActivities(ctx, pi.ID)
	if len(activities) != 1 {
		t.Fatalf("expected 1 activity, got %d", len(activities))
	}
	if err := e.CompleteTask(ctx, activities[0].ID, nil); err != nil {
		t.Fatalf("CompleteTask: %v", err)
	}
	pi, _ = s.GetProcessInstance(ctx, pi.ID)
	if pi.State != instance.ProcessInstanceStateCompleted {
		t.Errorf("expected completed, got %q", pi.State)
	}
}
